import requests
import pandas as pd
from io import StringIO

DEFAULT_LIPIDMAPS_URL = "https://www.lipidmaps.org/ms/rest/ms_search/"

def _get_num_matches(db, mzStr, adducts, tolerance=0.001):
    """Return the number of unique matched m/z values from the database
    for the given parameters."""
    try:
        url = LIPIDMAPS_URL
    except NameError:
        url = DEFAULT_LIPIDMAPS_URL

    files = {
        'CHOICE': (None, db),
        'ion': (None, adducts),
        'file': ('mz.txt', StringIO(mzStr), 'text/plain'),
        'tol': (None, str(tolerance)),
        'sort': (None, 'DELTA')
    }

    try:
        response = requests.post(url, files=files)
    except Exception:
        raise Exception(
            'Connection error with the database. Please check your network and try again after a few minutes.'
        )

    if len(response.text) == 0:
        return 0

    matches = pd.read_csv(StringIO(response.text), sep='\t', engine='python', index_col=False)
    if matches.empty:
        return 0

    # Determine the column containing matched masses
    if 'Mass' in matches.columns:
        matched_mass_col = matches['Mass']
    elif 'Matched Mass' in matches.columns:
        matched_mass_col = matches['Matched Mass']
    else:
        # If column not found, assume the second column (index 1) is matched mass
        matched_mass_col = matches.iloc[:, 1] if matches.shape[1] > 1 else matches.iloc[:, 0]

    # Convert to numeric, drop non-numeric and NaN
    numeric_masses = pd.to_numeric(matched_mass_col, errors='coerce').dropna().unique()
    return len(numeric_masses)


def main():
    db = 'GLYCOLIPIDS'
    mz_values = '1e2\n2e2\n3e2'
    adducts = 'M+H,M+Na'
    tolerance = 0.01
    num_matches = _get_num_matches(db, mz_values, adducts, tolerance)
    print(f'Number of unique m/z matches: {num_matches}')


if __name__ == '__main__':
    main()
